UPDATE tools SET
  short_description = COALESCE($q$Freshservice is Freshworks' cloud-based IT service management (ITSM) and enterprise service management platform, covering incident, problem, change, and asset management with ITIL-aligned workflows and AI assistance.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
