INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Customizable invoicing$q$, $q$Create branded, recurring invoices with multi-currency and multi-language support, and automated payment reminders.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Integrated online payments$q$, $q$Accept credit card, ACH, and other payment types directly on invoices through FreshBooks Payments.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Time tracking$q$, $q$Log billable hours and convert them straight into client invoices without manual data entry.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Expense tracking and receipt scanning$q$, $q$Capture receipts via mobile app, import bank transactions, and auto-categorize expenses for tax reporting.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Project management and collaboration$q$, $q$Share project timelines, files, and communication with clients and team members inside FreshBooks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Financial and accounting reports$q$, $q$Generate profit and loss statements, balance sheets, and tax-ready reports (available on Plus and above).$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Proposals and retainers$q$, $q$Send proposals that convert into invoices and set up recurring client retainers on Plus and higher plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Mobile apps$q$, $q$Native iOS and Android apps for invoicing, expense capture, mileage tracking, and client communication on the go.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Very easy to learn for non-accountants, with a clean, freelancer-friendly interface$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Strong time-tracking-to-invoice workflow that reduces manual billing work$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Responsive customer support frequently cited in user reviews$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Mobile apps cover most day-to-day tasks, including receipt and mileage capture$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Client caps on lower tiers (5 on Lite, 50 on Plus) force upgrades as a business grows$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Only one user included by default; additional team seats add recurring cost$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Less native accounting depth (inventory, payroll) than QuickBooks Online or Xero$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Advanced features like project profitability and custom email automation are gated behind the Premium tier$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$What is FreshBooks used for?$q$, $q$FreshBooks is cloud accounting and invoicing software used mainly by freelancers, consultants, and small service businesses to send invoices, track time and expenses, accept online payments, and generate basic financial reports.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$How much does FreshBooks cost?$q$, $q$As researched from FreshBooks' pricing page, the Lite plan is $23/month, Plus is $43/month, Premium is $70/month, and Select is custom-priced. Promotional discounts and a roughly 10% annual-billing discount are commonly available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Does FreshBooks have a free trial?$q$, $q$Yes, FreshBooks offers a 30-day free trial on its paid plans and does not require a credit card to start the trial.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Is FreshBooks good for growing teams, not just solo freelancers?$q$, $q$FreshBooks can support small teams, but each plan has a billable-client cap and only one included user seat, with additional team members billed separately, which can make it less cost-efficient for larger teams than accounting platforms built for bigger organizations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$What is the difference between FreshBooks and QuickBooks Online?$q$, $q$FreshBooks focuses on ease of use for invoicing-first small businesses and freelancers, while QuickBooks Online generally offers deeper native accounting, inventory, and payroll functionality aimed at a broader range of small-to-midsize businesses.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Who founded FreshBooks?$q$, $q$FreshBooks was founded by Mike McDerment along with Levi Cooperman and Joe Sawada in Toronto, starting in 2003, after McDerment struggled with existing invoicing tools at his own design business.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Freelance invoicing and payments$q$, $q$Independent consultants and creatives use FreshBooks to send professional invoices, accept online payments, and track which clients still owe money.$q$, $q$Freelancers and independent contractors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Time-based client billing$q$, $q$Service businesses that bill hourly use FreshBooks' integrated time tracker to log work and automatically generate accurate client invoices.$q$, $q$Consultants, agencies, and professional service firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Small business bookkeeping and tax prep$q$, $q$Small business owners use FreshBooks' expense tracking and financial reports to stay organized for tax season and share access with their accountant.$q$, $q$Small business owners and their accountants/bookkeepers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Lite$q$, $q$$23/month$q$, $q$Monthly (annual billing discount available)$q$, NULL, $q$["Up to 5 billable clients","Unlimited invoices and estimates","Expense tracking","Accept online payments","Tax reports"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Plus$q$, $q$$43/month$q$, $q$Monthly (annual billing discount available)$q$, NULL, $q$["Up to 50 billable clients","Proposals and client retainers","Financial and accounting reports","Receipt scanning automation","Accountant access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Premium$q$, $q$$70/month$q$, $q$Monthly (annual billing discount available)$q$, NULL, $q$["Unlimited billable clients","Customized email templates","Project profitability tracking","Automated client emails","Bill receipt scanning with line items"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$Select$q$, $q$Custom (contact sales)$q$, $q$Annual contract$q$, NULL, $q$["Unlimited billable clients","Lower credit card transaction fees","Dedicated phone support","2 team member accounts included","Remove FreshBooks branding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FreshBooks is a Toronto-founded cloud accounting and invoicing platform built originally for freelancers and small service businesses. It started in 2003 as a simple invoicing tool after founder Mike McDerment lost an invoice and could not find good web-based software to replace it, and has since grown into a broader small-business accounting suite covering invoicing, expenses, time tracking, and reporting.$q$, $q$The company was bootstrapped for its first several years before raising a $30 million Series A round in 2014 led by Oak Investment Partners. It remains privately held and headquartered in Toronto, Canada, serving customers primarily across North America, Europe, and Australia.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$FreshBooks centers on customizable, recurring invoicing with support for multiple currencies and languages, paired with integrated online payment acceptance through FreshBooks Payments (credit card, ACH, and more).$q$, $q$Time tracking is built directly into the billing workflow, so tracked hours convert into invoice line items without manual re-entry, and expense tracking uses mobile receipt scanning and bank imports to automate categorization for tax time.$q$, $q$Higher-tier plans add double-entry accounting reports, project profitability tracking, client retainers and proposals, and accountant-collaboration access, while mobile apps for iOS and Android extend the platform to on-the-go invoicing and mileage tracking.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$FreshBooks uses a four-tier structure: Lite ($23/month, 5 billable clients), Plus ($43/month, 50 billable clients, most popular), Premium ($70/month, unlimited billable clients), and Select (custom pricing for larger teams with dedicated support and lower payment fees).$q$, $q$All plans include one user by default, with additional team members billed at $11/user/month. FreshBooks offers a 30-day free trial with no credit card required, an annual-billing discount of roughly 10%, and add-ons such as Advanced Payments ($20/month) and Payroll (from $40/month).$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c9d6721c-323e-461a-9e3f-5f4dfc9baedb', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Omnichannel shared inbox$q$, $q$Consolidate email, live chat, phone, WhatsApp, and social messages into one ticketing view for the whole support team.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Collision detection and SLA management$q$, $q$Prevent duplicate replies and keep response times on track with automated service-level agreement policies.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Freddy AI Copilot and self-service agent$q$, $q$AI-assisted reply drafting and ticket summarization for agents, plus an AI bot that resolves common customer questions automatically.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Automation and workflow rules$q$, $q$Rule-based ticket routing, prioritization, and canned responses reduce manual triage work.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Knowledge base and customer portal$q$, $q$Self-service articles and forums let customers find answers without opening a ticket.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Field service management$q$, $q$Schedule and dispatch on-site technicians and track field jobs alongside standard support tickets.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Reporting and analytics$q$, $q$Dashboards track ticket volume, CSAT, agent performance, and SLA compliance over time.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Multi-language, multi-brand support$q$, $q$Manage support across multiple brands and languages from a single Freshdesk account on higher tiers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Lower entry price than Zendesk with a comparable core feature set$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Fast to set up and learn, with an intuitive agent interface$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Strong automation and self-service tools even on mid-tier plans$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Broad channel coverage (email, chat, phone, social, WhatsApp)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Permanent free plan was discontinued in 2025, replaced with a time-limited free program$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Freddy AI Copilot is a separate paid add-on rather than bundled in lower tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Enterprise-grade features (sandboxing, advanced security, audit logs) require the top tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Per-agent pricing can get expensive quickly for larger support teams$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Is Freshdesk free?$q$, $q$Freshdesk no longer offers a permanent free plan. As of the 2025 changes, it offers a free program limited to 1-2 agents for six months, after which teams must upgrade to a paid plan starting at $19 per agent per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$What are Freshdesk's pricing tiers?$q$, $q$As researched, Freshdesk's current paid tiers are Growth ($19/agent/month), Pro ($55/agent/month), and Enterprise ($89/agent/month), all billed annually, with a separate Freddy AI Copilot add-on at $29/agent/month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Who owns Freshdesk?$q$, $q$Freshdesk is owned and operated by Freshworks Inc., the publicly traded company (Nasdaq: FRSH) that Freshdesk's founders renamed themselves to in 2017 after expanding into multiple products.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$How is Freshdesk different from Zendesk?$q$, $q$Freshdesk and Zendesk offer similar omnichannel ticketing capabilities, but Freshdesk is generally positioned as the more affordable option with a simpler setup process, while Zendesk is often seen as more enterprise-grade and highly customizable.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Does Freshdesk include AI features?$q$, $q$Yes, Freshdesk includes Freddy AI capabilities such as an AI copilot for agents and an AI self-service bot for customers, though the AI Copilot is priced as a separate add-on on most plans.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Who founded Freshdesk?$q$, $q$Freshdesk was founded in October 2010 in Chennai, India, by Girish Mathrubootham and Shan Krishnasamy, who later renamed the parent company Freshworks Inc. in 2017.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Multi-channel customer support$q$, $q$Support teams use Freshdesk to manage email, chat, phone, and social inquiries from a single shared inbox with automated routing.$q$, $q$Customer support and service teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Self-service deflection$q$, $q$Companies build knowledge bases and deploy Freddy AI's self-service bot to resolve common questions without agent involvement.$q$, $q$SMB and mid-market support organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Field service coordination$q$, $q$Businesses with on-site technicians use Freshdesk's field service management to schedule jobs alongside standard support tickets.$q$, $q$Field service and hybrid support operations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Free Program$q$, $q$Free$q$, $q$Limited to 6 months$q$, NULL, $q$["Up to 2 agents","Core ticketing","Basic knowledge base","Pre-built reports","Email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Growth$q$, $q$$19/agent/month$q$, $q$Annual$q$, NULL, $q$["Team collaboration","Automation rules","Knowledge base","Basic reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Pro$q$, $q$$55/agent/month$q$, $q$Annual$q$, NULL, $q$["Multiple ticket views","Custom roles","Advanced automation","CSAT surveys","Field service management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$Enterprise$q$, $q$$89/agent/month$q$, $q$Annual$q$, NULL, $q$["Advanced security and sandboxing","Audit logs","Skill-based routing","Approval workflows"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Freshdesk is Freshworks' original flagship product: an omnichannel customer support helpdesk that unifies email, chat, phone, WhatsApp, and social conversations into a shared ticketing inbox. It launched in October 2010 in Chennai, India, founded by Girish Mathrubootham and Shan Krishnasamy, and grew into the foundation of what became Freshworks Inc. after its 2017 rebrand.$q$, $q$Freshworks now operates as a dual-headquartered, publicly traded company (Nasdaq: FRSH since September 2021), with global headquarters in San Mateo, California and a major engineering base in Chennai, India.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Freshdesk's ticketing system centers on a shared team inbox with collision detection, SLA policies, canned responses, and rule-based automation for routing and prioritizing tickets across email, chat, phone, and social channels.$q$, $q$'Freddy AI' spans the platform: an AI self-service agent for customers, an AI copilot that helps human agents draft and summarize replies, and AI-driven insights for support managers, alongside a self-service knowledge base, customer portal, field service scheduling, and performance reporting dashboards.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Freshdesk previously offered a permanent free 'Sprout' plan, but as of 2025 that was replaced with a free program limited to 1-2 agents for six months. Paid plans are Growth ($19/agent/month), Pro ($55/agent/month), and Enterprise ($89/agent/month), all billed annually, with monthly billing costing roughly 20% more.$q$, $q$Freddy AI Copilot is a $29/agent/month add-on across plans. Freshdesk Omni, the fuller omnichannel bundle, is priced separately at roughly $29, $79, and $119 per agent per month across its own tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
