INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3462f64d-8a5d-4bf1-aaf2-9bbe35c19498', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Self-hosted, open-source core$q$, $q$Full control over data and infrastructure, released under the AGPLv3 license with no vendor lock-in.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Multi-user support$q$, $q$A single install can serve multiple independent user accounts, useful for households, teams, or public instances.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Google Reader and Fever API compatibility$q$, $q$Connects to a large existing ecosystem of third-party mobile and desktop RSS reader apps without needing a dedicated FreshRSS client.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$WebSub push updates$q$, $q$Supports the WebSub standard for near-instant updates from compatible publishers instead of relying solely on polling.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$XPath-based web scraping$q$, $q$Generates feeds from websites that do not publish RSS or Atom natively, using custom XPath rules.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Custom tags and labels$q$, $q$Organize large feed collections with flexible tagging beyond simple folders.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Command-line interface and extensions$q$, $q$Scriptable admin tasks via CLI, plus a plugin system for community-built extensions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Flexible authentication$q$, $q$Supports standard form login, HTTP authentication, and OpenID Connect single sign-on.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Completely free with no subscription tiers or feature paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Full data ownership and privacy since it runs on infrastructure you control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Compatible with a large ecosystem of existing mobile RSS apps via API emulation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Actively maintained with a large, long-running open-source community$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Requires self-hosting expertise and ongoing server maintenance, unlike hosted readers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$No official first-party mobile app; relies on third-party clients$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$No built-in customer support channel beyond community forums and GitHub issues$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Initial setup and configuration is more technical than signing up for a hosted service$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Is FreshRSS really free?$q$, $q$Yes, FreshRSS is free, open-source software licensed under AGPLv3. The only cost is whatever hosting infrastructure you choose to run it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Who created FreshRSS?$q$, $q$FreshRSS was created by French developer Marien Fressinaud, who began the project in October 2012 and released the first stable 1.0 version in January 2015. It is now maintained by a community of contributors.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Does FreshRSS have a mobile app?$q$, $q$FreshRSS does not ship an official first-party mobile app, but its API is compatible with the Google Reader and Fever APIs, allowing many existing third-party RSS mobile apps to connect to a self-hosted FreshRSS instance.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$How is FreshRSS different from Miniflux or Tiny Tiny RSS?$q$, $q$FreshRSS, Miniflux, and Tiny Tiny RSS are all self-hosted, open-source feed readers. FreshRSS is generally considered feature-rich and actively maintained, with particularly strong third-party mobile app compatibility, while Miniflux favors minimalism and Tiny Tiny RSS has its own long-standing plugin ecosystem.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Can FreshRSS aggregate sites without an RSS feed?$q$, $q$Yes, FreshRSS includes native web-scraping support based on XPath rules, which can generate a feed from a website's HTML structure even if it does not publish RSS or Atom natively.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$How do I install FreshRSS?$q$, $q$FreshRSS can be installed via a traditional PHP web server setup (Apache or Nginx with PHP-FPM) or, more commonly among self-hosters, deployed using the project's official Docker image.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Privacy-focused personal news reading$q$, $q$Individuals who want to avoid tracking by commercial feed readers self-host FreshRSS to read blogs and news feeds under their own control.$q$, $q$Privacy-conscious individuals and power readers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Household or small team feed aggregation$q$, $q$Multi-user support lets a family or small team share one FreshRSS instance with separate logins and subscription lists.$q$, $q$Households, small teams, and community groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Aggregating sites without native RSS support$q$, $q$System administrators use FreshRSS's XPath scraping to build feeds for websites that do not publish RSS or Atom feeds.$q$, $q$Sysadmins and technical power users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A (open source)$q$, NULL, $q$["Unlimited feeds and articles","Multi-user support","API access","Extensions and plugins","Full source code access"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FreshRSS is a free, open-source, self-hosted RSS and Atom feed aggregator started by French developer Marien Fressinaud in October 2012, with its first stable 1.0 release arriving in January 2015. It is community-maintained on GitHub with no corporate ownership, distributed under the AGPLv3 license.$q$, $q$The project is designed to be lightweight enough for cheap shared hosting while still scaling to manage over a million articles and tens of thousands of feeds per instance, making it a popular choice among self-hosting and privacy-focused communities.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$FreshRSS supports multi-user accounts, an anonymous read-only sharing mode, custom tags/labels, a command-line interface, and an extension system for community plugins, along with flexible authentication including OpenID Connect.$q$, $q$Its API layer emulates the Google Reader and Fever APIs, giving it broad compatibility with existing third-party mobile and desktop RSS apps, and it supports WebSub for instant push updates plus native XPath-based web scraping for sites without a published feed.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$FreshRSS itself is entirely free and open source; there are no subscription tiers or paid feature gates. Users only pay for the hosting infrastructure they choose to run it on, whether a home server, a small VPS, or a Docker-based deployment, which the project officially supports via a published Docker image.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('98aaa86f-78de-4ac7-a8a6-37ad046c4363', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Visual deal pipelines$q$, $q$Customizable, drag-and-drop pipelines to track deals through each stage of the sales process.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Built-in phone and email$q$, $q$Call and email prospects directly from the CRM without needing separate dialer or email tools.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Freddy AI lead scoring$q$, $q$AI ranks leads and contacts by likelihood to convert, helping reps prioritize outreach (Pro tier and above).$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Sales sequences$q$, $q$Automated, multi-step outreach campaigns combining email and other touchpoints (Pro tier and above).$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Multiple pipelines and territory management$q$, $q$Manage distinct sales processes for different products, regions, or teams within one account.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Custom modules$q$, $q$Model unique business objects beyond standard contacts and deals on the Enterprise plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Workflow automation$q$, $q$Automate repetitive tasks like follow-up reminders, field updates, and lead assignment.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$AI-powered forecasting insights$q$, $q$Predictive analytics on deal likelihood and revenue forecasting for sales leadership (Enterprise tier).$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Free plan available for very small teams up to 3 users$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Lower cost than Salesforce at comparable functionality for SMBs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Built-in phone and email reduce need for separate sales tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Integrates natively with other Freshworks products (Freshdesk, Freshservice)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$AI lead scoring and sales sequences require upgrading to the Pro tier or higher$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Less deep customization and ecosystem than Salesforce for complex enterprise sales processes$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Marketing automation is a separate product (Freshmarketer), not bundled into Freshsales$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Free and Growth tiers lack advanced reporting$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Is Freshsales free?$q$, $q$Yes, Freshsales offers a free plan for up to 3 users with basic contact and deal management, a built-in phone, and email integration, though it lacks automation, sales sequences, and AI features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$What are Freshsales' pricing tiers?$q$, $q$As researched, Freshsales offers Free (3 users), Growth ($9/user/month annual), Pro ($39/user/month annual), and Enterprise ($59/user/month annual), all with a 21-day free trial on paid plans.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$When was Freshsales launched?$q$, $q$Freshsales launched in 2016 as Freshworks' second major product, following the 2010 launch of Freshdesk.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$How does Freshsales compare to HubSpot CRM?$q$, $q$Freshsales generally emphasizes AI-driven sales efficiency (via Freddy AI) at a lower price point, while HubSpot CRM leads with strong inbound marketing automation and a broader free tier, but can become more expensive as businesses add additional HubSpot Hubs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Does Freshsales include AI features?$q$, $q$Yes, Freshsales includes Freddy AI-powered lead scoring starting on the Pro plan, along with AI-powered forecasting insights on the Enterprise plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Who makes Freshsales?$q$, $q$Freshsales is made by Freshworks Inc., the publicly traded company (Nasdaq: FRSH) that also makes Freshdesk, Freshservice, and Freshmarketer.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Small sales team pipeline management$q$, $q$Small teams use Freshsales' free or Growth plan to track contacts and deals through a visual pipeline without heavy setup.$q$, $q$Small business sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$AI-assisted lead prioritization$q$, $q$Growing sales organizations use Freddy AI lead scoring and sales sequences on the Pro plan to prioritize outreach and automate follow-ups.$q$, $q$Mid-market sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Multi-region or multi-product sales operations$q$, $q$Larger sales organizations use Freshsales Enterprise's multiple pipelines, territory management, and custom modules to model complex sales structures.$q$, $q$Enterprise and multi-team sales organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 3 users","Contact and deal management","Built-in phone","Email integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Growth$q$, $q$$9/user/month$q$, $q$Annual$q$, NULL, $q$["Web forms","Basic workflow automation","SMS and WhatsApp integration","Product catalog"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Pro$q$, $q$$39/user/month$q$, $q$Annual$q$, NULL, $q$["Freddy AI lead scoring","Sales sequences","Multiple sales pipelines","Territory management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$Enterprise$q$, $q$$59/user/month$q$, $q$Annual$q$, NULL, $q$["Custom modules","Field-level permissions","Sandbox environments","Audit logs","AI-powered forecasting insights"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Freshsales is Freshworks' sales-first CRM, launched in 2016 as the company's second major product after Freshdesk. It focuses on contact and deal management, built-in calling and email, and AI-powered lead scoring, rather than broad marketing automation, which Freshworks addresses through its separate Freshmarketer product.$q$, $q$Like Freshdesk, Freshsales is developed and sold by Freshworks Inc., the publicly traded (Nasdaq: FRSH) parent company headquartered in San Mateo, California with major engineering operations in Chennai, India.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core Freshsales features include visual, customizable deal pipelines, a built-in phone dialer, email integration, and a unified customer activity timeline. Higher tiers add Freddy AI lead scoring, automated sales sequences, multiple pipelines, and territory management.$q$, $q$Enterprise-tier capabilities include custom modules, field-level permissions, sandbox testing environments, audit logs, and AI-powered forecasting insights, aimed at larger or more compliance-sensitive sales organizations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Freshsales offers a Free plan for up to 3 users with basic CRM functionality. Paid tiers are Growth ($9/user/month annual), Pro ($39/user/month annual, the first tier with AI lead scoring and sales sequences), and Enterprise ($59/user/month annual, with custom modules and sandboxing).$q$, $q$All paid plans include a 21-day free trial, and monthly billing runs roughly 20% higher than the annual rates listed above.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3791efda-beab-41cb-b03c-14070ac10a70', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
