INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Incident and problem management$q$, $q$Log, triage, and resolve day-to-day IT issues, and identify root causes behind recurring problems.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Change and release management$q$, $q$Govern infrastructure and system changes with risk assessment and approval workflows (Pro tier and above).$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$IT asset management with CMDB$q$, $q$Track hardware, software, and their relationships across the organization in an integrated configuration management database.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Service catalog and self-service portal$q$, $q$Let employees request standardized IT services like new equipment or software access without opening a manual ticket.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Freddy AI Agent, Copilot, and Insights$q$, $q$AI-powered employee self-service, agent assistance, and predictive analytics on ticket trends (Enterprise tier).$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Workflow automator$q$, $q$No-code automation builder for ticketing and asset management processes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Enterprise service management (ESM)$q$, $q$Extend ticketing and service-catalog workflows beyond IT to HR, facilities, and other departments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$IT operations management (ITOM) add-on$q$, $q$Optional infrastructure monitoring and event correlation for unified IT operations visibility.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Faster implementation and simpler administration than ServiceNow$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Full ITIL process coverage (incident, problem, change, release) even outside the top tier$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Integrated CMDB and asset management included without third-party tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Extends naturally into enterprise service management for non-IT departments$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Freddy AI's full capability set is concentrated in the costly Enterprise tier$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Enterprise plan pricing is not public, requiring a sales conversation to budget accurately$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Less configurable and less deep than ServiceNow for very large, complex enterprises$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Change and release management require upgrading to the Pro tier or above$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$What is Freshservice used for?$q$, $q$Freshservice is IT service management (ITSM) software used by IT departments to manage incidents, problems, changes, releases, and IT assets through ITIL-aligned workflows, and increasingly extended to non-IT departments as enterprise service management.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$How much does Freshservice cost?$q$, $q$As researched, Freshservice's tiers are Starter ($19/agent/month annual), Growth ($49/agent/month annual), Pro ($99/agent/month annual), and Enterprise (custom pricing on request).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$When did Freshservice launch?$q$, $q$Freshservice launched in January 2014 as Freshworks' second major product, following the 2010 launch of Freshdesk.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$How does Freshservice compare to ServiceNow?$q$, $q$Freshservice offers faster implementation, simpler administration, and lower cost than ServiceNow, while ServiceNow generally offers greater configurability and depth suited to very large enterprises with dedicated ITSM teams.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Does Freshservice include AI tools?$q$, $q$Yes, Freshservice includes Freddy AI Agent, Copilot, and Insights, though the full AI suite is concentrated in the Enterprise plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Is there a free trial for Freshservice?$q$, $q$Yes, Freshservice offers a 14-day free trial with no credit card required across its plans.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$IT help desk and incident management$q$, $q$IT teams use Freshservice to log, prioritize, and resolve employee IT issues through structured incident management workflows.$q$, $q$IT support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$IT asset and configuration tracking$q$, $q$Organizations use Freshservice's CMDB and asset management to track hardware and software inventory and relationships.$q$, $q$IT operations and asset management teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Enterprise service management beyond IT$q$, $q$Non-IT departments like HR and facilities adopt Freshservice's service catalog and ticketing model for their own internal service requests.$q$, $q$HR, facilities, and other internal service teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Starter$q$, $q$$19/agent/month$q$, $q$Annual$q$, NULL, $q$["Basic ticketing","Knowledge management","Self-service portal"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Growth$q$, $q$$49/agent/month$q$, $q$Annual$q$, NULL, $q$["Asset management","Service catalog","Workflow automator"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Pro$q$, $q$$99/agent/month$q$, $q$Annual$q$, NULL, $q$["Change management","Problem management","Release management","Advanced reporting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Annual$q$, NULL, $q$["Freddy AI Agent, Copilot, and Insights","Sandbox environments","Audit logs","Advanced security controls"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Freshservice is Freshworks' IT service management (ITSM) platform, launched in January 2014 as the company's second major product after Freshdesk. It applies ITIL-aligned processes (incident, problem, change, and release management) with a cloud-native, easier-to-implement design than legacy ITSM incumbents.$q$, $q$Like the rest of the Freshworks portfolio, Freshservice is developed by the publicly traded Freshworks Inc. (Nasdaq: FRSH), headquartered in San Mateo, California with major engineering operations in Chennai, India.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core ITIL processes covered include incident, problem, change, and release management, alongside IT asset management (ITAM) with an integrated CMDB and a self-service catalog for employee requests.$q$, $q$Freddy AI capabilities (AI Agent for self-service, AI Copilot for agents, and AI Insights for analytics) are concentrated in the Enterprise tier, and Freshservice extends beyond IT into broader enterprise service management for departments like HR and facilities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Freshservice's tiers are Starter ($19/agent/month annual), Growth ($49/agent/month annual), Pro ($99/agent/month annual), and Enterprise (custom pricing, contact sales), each adding progressively deeper ITIL process coverage, asset management, and AI capability.$q$, $q$All plans include a 14-day free trial with no credit card required, and annual billing is reported to save roughly 35% versus monthly billing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
