INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('41501fa1-8a36-4631-b45d-fc12ce3657f5', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Multi-protocol federation$q$, $q$Communicates via native DFRN, the Diaspora protocol, ActivityPub, and legacy OStatus, bridging otherwise-separate networks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Long-form posts with rich formatting$q$, $q$No strict character limit, with rich text and BBCode formatting, unlike most microblogging-style Fediverse platforms.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Per-post privacy controls$q$, $q$Restrict individual posts to specific contacts or groups rather than applying one blanket audience setting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Photo albums and events calendar$q$, $q$Facebook-style media organization and event scheduling built into the core platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Group and forum pages$q$, $q$Community and forum-style pages for group discussions, distinct from individual profiles.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Email bridging via IMAP/SMTP$q$, $q$Read and reply to email threads as though they were social posts, connecting traditional email to the federated timeline.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Third-party network bridging$q$, $q$Add-ons connect Friendica to non-federated services such as Bluesky and Tumblr.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Self-hosting and public instance choice$q$, $q$Run your own Friendica instance or join an existing community-operated public node.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Completely free and open source with no corporate control or data monetization$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Broadest protocol interoperability of any major Fediverse platform, bridging multiple networks$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Long-form posts and Facebook-style features (albums, events, groups) not found on most Fediverse platforms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Fine-grained, per-post privacy controls for more nuanced audience management$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Smaller active user base than Mastodon, which can limit network effects and discoverability$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$No corporate backing means slower feature development and no dedicated support line$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Requires self-hosting knowledge if you want to run your own instance$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Interface and setup can feel dated or complex compared to more polished commercial social apps$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Is Friendica free to use?$q$, $q$Yes, Friendica is free, open-source software. You can join an existing public instance for free or self-host your own instance, with some public instances requesting voluntary donations for hosting costs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Who created Friendica?$q$, $q$Friendica was created in 2010 by developer Mike Macgirvin under the name Mistpark, later renamed Friendika and then Friendica. Macgirvin left the project in 2012, and it has been community-maintained since.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Does Friendica work with Mastodon?$q$, $q$Yes, Friendica added ActivityPub support in its December 2018 release, allowing it to federate bidirectionally with Mastodon and other ActivityPub-based Fediverse platforms.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$How is Friendica different from Mastodon?$q$, $q$Friendica supports long-form posts with rich text formatting and Facebook-style features like photo albums, events, and groups, whereas Mastodon is primarily a shorter, character-limited microblogging platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$How many people use Friendica?$q$, $q$According to federation-monitoring services, Friendica had roughly 99 active instances and around 2,000 to 5,000 active users over recent months as of mid-2026, though exact figures are inherently incomplete across the decentralized Fediverse.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$What license is Friendica released under?$q$, $q$Friendica is released under the GNU Affero General Public License version 3 (AGPLv3).$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Privacy-respecting personal social networking$q$, $q$Individuals who want to avoid corporate-controlled social platforms use Friendica for long-form posting with fine-grained privacy controls.$q$, $q$Privacy-conscious individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Bridging multiple federated networks$q$, $q$Users who want to interact with contacts across Mastodon, Diaspora, and other networks from one place use Friendica as a protocol bridge.$q$, $q$Fediverse power users and community managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Community and group hosting$q$, $q$Communities use Friendica's group/forum pages and events calendar to organize discussions and gatherings outside corporate platforms.$q$, $q$Online communities and interest groups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$Self-Hosted or Public Instance$q$, $q$Free$q$, $q$N/A (open source; some public instances accept donations)$q$, NULL, $q$["Unlimited posts","Multi-protocol federation","Photo albums and events","Group pages","Full source code access"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Friendica is a free, open-source, decentralized social networking platform originally created in 2010 by Mike Macgirvin under the name Mistpark, later renamed Friendika and then Friendica. It is part of the Fediverse and is now maintained entirely by a volunteer community with no corporate or foundation backing.$q$, $q$Friendica's defining feature is broad protocol interoperability: it federates via its native DFRN protocol, the Diaspora protocol, ActivityPub (added December 2018, connecting it to Mastodon and other major Fediverse platforms), and legacy OStatus, plus bridges to services like email, Bluesky, and Tumblr through add-ons.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Unlike character-limited microblogging platforms, Friendica supports long-form posts with rich text and BBCode formatting, along with Facebook-style features including photo albums, an events calendar, and group/forum pages.$q$, $q$Fine-grained, per-post privacy controls let users restrict individual posts to specific contacts or groups, and Friendica can bridge otherwise-incompatible networks together, acting as a connective layer across the wider decentralized and even non-federated social web.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Friendica is entirely free, open-source software released under the AGPLv3 license. There are no subscription tiers; users either self-host their own instance ('pod') or join one of many independently run public instances, some of which request voluntary donations to cover hosting costs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7c0016ff-460a-49f3-a0f2-026bb26769d9', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Ideas board with voting$q$, $q$Customers and internal stakeholders submit and vote on feature requests and product ideas in one central board.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$2D prioritization matrix$q$, $q$Score ideas on custom benefit and cost factors and visualize them as quick wins, major projects, or time sinks.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Revenue-weighted voting$q$, $q$Weight customer votes by revenue or plan tier so higher-value customers' feedback carries more signal.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Public roadmap$q$, $q$Publish a branded, customer-facing roadmap showing what's planned, in progress, and shipped.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$In-product changelog (Announcements)$q$, $q$Publish updates about shipped features directly to users through an embeddable widget.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$In-app surveys$q$, $q$Run NPS, CSAT, Idea Polls, Quick Polls, and Open Feedback surveys embedded directly in your product.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Embeddable widget$q$, $q$Collect feedback, ideas, and survey responses in context inside your own product rather than a separate external site.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$White-labeling$q$, $q$Remove Frill branding and customize the domain for a fully native-feeling feedback experience (Growth tier or add-on).$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Affordable entry price relative to more established feedback-board competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Built-in 2D prioritization matrix helps teams make evidence-based roadmap decisions$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Simple, lightweight setup suited to small SaaS teams without a dedicated product-ops function$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Combines feedback, roadmap, changelog, and surveys in one tool instead of several point solutions$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$No permanent free plan, only a 14-day trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Ideas board is capped at 50 on the entry-level Startup plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$White-labeling and extra surveys are paid add-ons on lower tiers, raising effective cost$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Smaller brand recognition and ecosystem than established competitors like Canny or UserVoice$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$What is Frill used for?$q$, $q$Frill is used by product and SaaS teams to collect and prioritize customer feedback and feature requests, publish a public roadmap, share product updates via an in-product changelog, and run in-app surveys like NPS and CSAT.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$How much does Frill cost?$q$, $q$As researched, Frill's plans are Startup ($25/month, 50 ideas), Business ($49/month, unlimited ideas), Growth ($149/month, most features bundled), and Enterprise ($349+/month). There is no permanent free plan, but a 14-day free trial is available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Who founded Frill?$q$, $q$Frill was founded in January 2021 by Mike Hill, a Sydney, Australia-based entrepreneur who also founded Curator.io and the digital agency Holler.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Does Frill have a free plan?$q$, $q$No, Frill does not have a permanent free plan; it offers a 14-day free trial that does not require a credit card.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$How is Frill different from Canny?$q$, $q$Frill and Canny both offer feedback boards, public roadmaps, and changelogs, but Frill is generally positioned as a more affordable, lightweight option, while Canny has a longer market history and broader feature set aimed at a wider range of company sizes.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Does Frill support customer surveys?$q$, $q$Yes, Frill includes in-app surveys covering NPS, CSAT, Idea Polls, Quick Polls, and Open Feedback formats, embeddable directly inside your product.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Startup feature request management$q$, $q$Early-stage SaaS teams use Frill's Ideas board to collect and prioritize feature requests from a growing user base.$q$, $q$SaaS startups and small product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Public roadmap transparency$q$, $q$Product teams publish a branded public roadmap to reduce duplicate requests and build customer trust around what's coming next.$q$, $q$Product managers and customer-facing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$In-app customer sentiment tracking$q$, $q$Teams embed NPS and CSAT surveys directly in their product to continuously measure customer satisfaction.$q$, $q$Product and customer success teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Startup$q$, $q$$25/month$q$, $q$Monthly$q$, NULL, $q$["Up to 50 ideas","1 survey","Ideas board","Public roadmap","Announcements"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Business$q$, $q$$49/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited ideas","Everything in Startup","Additional survey capacity"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Growth$q$, $q$$149/month$q$, $q$Monthly$q$, NULL, $q$["White-labeling included","Everything in Business","Higher usage limits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$Enterprise$q$, $q$$349+/month$q$, $q$Monthly$q$, NULL, $q$["Highest usage limits","Dedicated support","Advanced customization"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Frill is a customer feedback and product management platform founded in January 2021 by Sydney, Australia-based entrepreneur Mike Hill, who previously built the digital agency Holler and the social media aggregation tool Curator.io. Frill appears to be an independently owned, bootstrapped SaaS product rather than a venture-funded company.$q$, $q$The platform combines an ideas board, public roadmap, in-product changelog (Announcements), and in-app survey tools into one lightweight package aimed primarily at SaaS startups and small product-led teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Frill's Ideas board lets customers submit and vote on feature requests, with a built-in 2D prioritization matrix that scores ideas by custom benefit and cost factors and can weight votes by customer revenue.$q$, $q$The Roadmap module publishes accepted ideas to a branded, public-facing page, while Announcements functions as an embeddable in-product changelog, and the survey tools cover NPS, CSAT, Idea Polls, Quick Polls, and Open Feedback formats.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Frill has no permanent free plan but offers a 14-day free trial. Paid tiers are Startup ($25/month, 50 ideas, 1 survey), Business ($49/month, unlimited ideas), Growth ($149/month, most features bundled including white-labeling), and Enterprise ($349+/month).$q$, $q$White-labeling and additional surveys are billed as add-ons on the Startup and Business tiers, which can raise the effective cost above the sticker price for growing teams.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
