INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('03aaf3ac-9023-4be0-9d5d-f55fb6fecd05', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Collaborative shared inbox$q$, $q$Unify email, SMS, live chat, social, and WhatsApp messages into one team-visible inbox instead of a personal mailbox or isolated ticket queue.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Live Activity presence$q$, $q$See in real time when a teammate is viewing or drafting a reply to prevent duplicate responses to the same message.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Shared drafts and internal comments$q$, $q$Co-author replies and discuss a conversation internally with @-mentions before sending anything to the customer.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Front AI Copilot$q$, $q$AI-generated suggested responses that speed up agent reply drafting across channels.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Autopilot AI agent$q$, $q$An omnichannel AI agent capable of resolving routine conversations with reduced human involvement.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Smart CSAT and Smart QA$q$, $q$Automatically infer customer satisfaction and evaluate response quality without manual review of every conversation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Automated routing and rules$q$, $q$Route incoming messages to the right team or person automatically based on configurable rules.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Analytics dashboards$q$, $q$Track team response times, workload distribution, and conversation volume trends.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Email-native, collaborative interface feels more familiar than ticket-queue helpdesks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Live Activity and shared drafts genuinely reduce duplicate replies and internal friction$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Strong omnichannel coverage (email, SMS, chat, social, WhatsApp, voice)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Well-capitalized company with a long operating history and enterprise-ready feature set$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Several AI features (Copilot, Smart QA, Smart CSAT) are priced as separate add-ons on lower tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Seat caps on Starter (10) and Professional (50) can force early upgrades for growing teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Per-seat Enterprise pricing ($105/seat/month) is expensive at scale compared to some ticket-based competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Less purpose-built for complex ITSM or multi-department ticketing workflows than dedicated helpdesk platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$What is Front used for?$q$, $q$Front is used by support, sales, and operations teams as a collaborative shared inbox that unifies email, SMS, chat, social, and WhatsApp messages, with AI tools for drafting replies, routing, and quality analysis.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$How much does Front cost?$q$, $q$As researched, Front's 2026 pricing is Starter ($25/seat/month, 10 seats), Professional ($65/seat/month, 50 seats), and Enterprise ($105/seat/month, unlimited seats), all on annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Who founded Front?$q$, $q$Front was founded in October 2013 by Mathilde Collin and Laurent Perrin, launching publicly in 2014 after going through Y Combinator.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Is Front's AI included in the base price?$q$, $q$Not entirely; on the Starter and Professional plans, AI features like Copilot, Smart QA, and Smart CSAT are priced as separate add-ons rather than bundled into the base seat price.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$How is Front different from Zendesk or Freshdesk?$q$, $q$Front is built around an email-native, collaborative shared inbox with features like Live Activity and shared drafts, whereas Zendesk and Freshdesk are more traditionally ticket-centric helpdesk platforms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Who is Front's CEO?$q$, $q$Dan O'Connell became Front's CEO in 2024, with co-founder Mathilde Collin transitioning to the role of executive chair.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Collaborative customer support inbox$q$, $q$Support teams use Front's shared inbox with Live Activity and assignment to coordinate replies without duplicating work.$q$, $q$Customer support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Omnichannel customer communication$q$, $q$Teams consolidate email, SMS, chat, social, and WhatsApp into Front's unified inbox to manage all customer channels in one place.$q$, $q$Support and customer operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$AI-assisted reply drafting and QA$q$, $q$Teams use Front AI's Copilot and Smart QA to speed up response drafting and automatically evaluate conversation quality at scale.$q$, $q$Growing support organizations wanting to control operational costs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Starter$q$, $q$$25/seat/month$q$, $q$Annual (10-seat cap)$q$, NULL, $q$["Shared inbox","Email channel","Basic automation","Analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Professional$q$, $q$$65/seat/month$q$, $q$Annual (50-seat cap)$q$, NULL, $q$["Omnichannel messaging (SMS, chat, social, WhatsApp)","Advanced automation","Live Activity","Shared drafts"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$Enterprise$q$, $q$$105/seat/month$q$, $q$Annual (unlimited seats)$q$, NULL, $q$["Unlimited seats","Advanced security and permissions","Dedicated support","Custom integrations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Front was founded in October 2013 by Mathilde Collin and Laurent Perrin, launching publicly in June 2014 after going through Y Combinator. The company is headquartered in San Francisco and has raised approximately $204 million in venture funding from investors including Sequoia Capital, Battery Ventures, and Salesforce Ventures, reaching a reported valuation of roughly $1.7 billion.$q$, $q$Dan O'Connell became CEO in 2024, with co-founder Mathilde Collin transitioning to executive chair. Front positions itself as a 'customer operations' platform spanning support, sales, and account management rather than a pure support helpdesk.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Front's core is a collaborative shared inbox unifying email, SMS, live chat, social, and WhatsApp messages, with assignment, Live Activity presence indicators, @-mentions, internal comments, and shared drafts for team collaboration on each conversation.$q$, $q$Front AI adds Topics for automatic message categorization, Copilot for AI-suggested replies, Autopilot as an omnichannel AI agent, and Smart CSAT/Smart QA for automated satisfaction and quality scoring, layered on top of routing automation and analytics dashboards.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Front moved to a simplified three-tier structure in 2026: Starter ($25/seat/month, 10-seat cap), Professional ($65/seat/month, 50-seat cap), and Enterprise ($105/seat/month, unlimited seats), all on annual billing with up to 24% savings over monthly.$q$, $q$On Starter and Professional, AI features like Copilot ($20/seat/month), Smart QA ($20/seat/month), and Smart CSAT ($10/seat/month) are priced as separate add-ons, with a bundled QA+CSAT option at $25/seat/month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e36a0c09-82ff-48bd-9da0-38f045bb10a2', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
